n    # 计算True Range\\n    tr1 = high[1:] - low[1:]\\n    tr2 = np.abs(high[1:] - close[:-1])\\n    tr3 = np.abs(low[1:] - close[:-1])\\n    tr = np.maximum(tr1, np.maximum(tr2, tr3))\\n    \\n    # 计算方向移动\\n    up_move = high[1:] - high[:-1]\\n    down_move = low[:-1] - low[1:]\\n    \\n    plus_dm = np.where((up_move > down_move) & (up_move > 0), up_move, 0)\\n    minus_dm = np.where((down_move > up_move) & (down_move > 0), down_move, 0)\\n    \\n    # Wilder平滑\\n    def wilder_smooth(data, period):\\n        smoothed = np.zeros(len(data))\\n        smoothed[period-1] = np.sum(data[:period])\\n        for i in range(period, len(data)):\\n            smoothed[i] = smoothed[i-1] - smoothed[i-1]/period + data[i]\\n        return smoothed\\n    \\n    if len(tr) < period:\\n        return 0\\n    \\n    atr = wilder_smooth(tr, period)\\n    plus_di_smooth = wilder_smooth(plus_dm, period)\\n    minus_di_smooth = wilder_smooth(minus_dm, period)\\n    \\n    # 计算DI+和DI-\\n    plus_di = 100 * plus_di_smooth / atr\\n    minus_di = 100 * minus_di_smooth / atr\\n    \\n    # 计算DX\\n    dx = 100 * np.abs(plus_di - minus_di) / (plus_di + minus_di + 1e-10)\\n    \\n    # 计算ADX（DX的平滑）\\n    adx = wilder_smooth(dx, period)\\n    \\n    # 返回最新的ADX值\\n    return adx[-1] if len(adx) > 0 else 0\\n\\n# 计算单只股票的指标\\ndef calculate_stock_metrics(code, end_date='2024-12-09'):\\n    \\\"\\\"\\\"计算单只股票的各项指标\\\"\\\"\\\"\\n    try:\\n        # 获取足够的历史数据（至少60+20=80天，考虑节假日取120天）\\n        bars = client.bars(symbol=code, frequency=9, offset=120)\\n        \\n        if bars is None or len(bars) < 60:\\n            return None\\n        \\n        # 按日期排序（使用索引）\\n        bars = bars.sort_index()\\n        \\n        # 截取到指定日期\\n        bars = bars[bars.index <= end_date]\\n        \\n        if len(bars) < 60:\\n            return None\\n        \\n        # 取最近的数据\\n        recent_60 = bars.tail(60)\\n        recent_20 = bars.tail(20)\\n        recent_5 = bars.tail(5)\\n        \\n        # 1. 价格强度：近20日涨幅\\n        price_change_20d = (recent_20['close'].iloc[-1] / recent_20['close'].iloc[0] - 1) * 100\\n        \\n        # 2. 量能强度：换手率比值\\n        # 换手率 = 成交量 / 流通股本，这里用成交量作为代理\\n        turnover_20d = recent_20['vol'].mean()\\n        turnover_60d = recent_60['vol'].mean()\\n        turnover_ratio = turnover_20d / (turnover_60d + 1e-10)\\n        \\n        # 3. 趋势强度：ADX指标\\n        adx_value = calculate_adx(recent_60, period=14)\\n        \\n        # 4. 资金强度：用近5日成交量增减率代理\\n        vol_change_5d = (recent_5['vol'].iloc[-1] / recent_5['vol'].iloc[0] - 1) * 100\\n        \\n        return {\\n            'code': code,\\n            'price_change_20d': price_change_20d,\\n            'turnover_ratio': turnover_ratio,\\n            'adx': adx_value,\\n            'vol_change_5d': vol_change_5d\\n        }\\n    except Exception as e:\\n        print(f\\\"Error processing {code}: {e}\\\")\\n        return None\\n\\n# 获取PE数据\\ndef get_pe_data(code):\\n    \\\"\\\"\\\"获取PE数据\\\"\\\"\\\"\\n    try:\\n        # 尝试获取财务数据\\n        finance = client.financial(symbol=code)\\n        if finance is not None and len(finance) > 0:\\n            pe = finance['pe'].iloc[0] if 'pe' in finance.columns else None\\n            return pe\\n    except:\\n        pass\\n    return None\\n\\nprint(\\\"开始获取创业板股票列表...\\\")\\nchinext_stocks = get_chinext_stocks()\\nprint(f\\\"共获取 {len(chinext_stocks)} 只创业板股票\\\")\\n\\n# 计算所有股票的指标\\nprint(\\\"\\\\n开始计算各股票指标...\\\")\\nresults = []\\nfor idx, row in chinext_stocks.iterrows():\\n    code = row['code']\\n    name = row['name']\\n    \\n    # 排除ST股票\\n    if 'ST' in name or '*ST' in name:\\n        continue\\n    \\n    print(f\\\"处理 {code} {name}...\\\", end='\\\\r')\\n    \\n    metrics = calculate_stock_metrics(code)\\n    if metrics is None:\\n        continue\\n    \\n    # 获取PE\\n    pe = get_pe_data(code)\\n    \\n    metrics['name'] = name\\n    metrics['pe'] = pe\\n    results.append(metrics)\\n\\nprint(f\\\"\\\\n成功计算 {len(results)} 只股票的指标\\\")\\n\\n# 转换为DataFrame\\ndf = pd.DataFrame(results)\\n\\n# 过滤PE条件\\ndf = df[df['pe'].notna()]\\ndf = df[(df['pe'] > 0) & (df['pe'] < 60)]\\n\\nprint(f\\\"PE筛选后剩余 {len(df)} 只股票\\\")\\n\\nif len(df) == 0:\\n    print(\\\"没有符合条件的股票\\\")\\n    result_path = '/Users/tomato/Documents/potato/project/YFD/yfd-agent-consensus/results/agent_consensus_batch/default_run/task_30_composite_scoring/independent/ga/composite_score.txt'\\n    with open(result_path, 'w', encoding='utf-8') as f:\\n        f.write(\\\"无符合条件的股票\\\\n\\\")\\nelse:\\n    # 计算百分位排名\\n    df['price_score'] = df['price_change_20d'].rank(pct=True) * 40\\n    df['turnover_score'] = df['turnover_ratio'].rank(pct=True) * 30\\n    df['trend_score'] = (df['adx'] / 100) * 20\\n    df['fund_score'] = df['vol_change_5d'].rank(pct=True) * 10\\n    \\n    # 计算总分\\n    df['total_score'] = df['price_score'] + df['turnover_score'] + df['trend_score'] + df['fund_score']\\n    \\n    # 筛选总分>75\\n    df = df[df['total_score'] > 75]\\n    \\n    print(f\\\"总分筛选后剩余 {len(df)} 只股票\\\")\\n    \\n    if len(df) == 0:\\n        result_path = '/Users/tomato/Documents/potato/project/YFD/yfd-agent-consensus/results/agent_consensus_batch/default_run/task_30_composite_scoring/independent/ga/composite_score.txt'\\n        with open(result_path, 'w', encoding='utf-8') as f:\\n            f.write(\\\"无符合条件的股票（总分>75）\\\\n\\\")\\n    else:\\n        # 按总分降序排序，取前15\\n        df = df.sort_values('total_score', ascending=False).head(15)\\n        \\n        # 输出结果\\n        result_path = '/Users/tomato/Documents/potato/project/YFD/yfd-agent-consensus/results/agent_consensus_batch/default_run/task_30_composite_scoring/independent/ga/composite_score.txt'\\n        with open(result_path, 'w', encoding='utf-8') as f:\\n            f.write(\\\"股票代码,价格强度分,量能强度分,趋势强度分,资金强度分,总分,PE\\\\n\\\")\\n            for _, row in df.iterrows():\\n                f.write(f\\\"{row['code']},{row['price_score']:.1f},{row['turnover_score']:.1f},\\\"\\n          